package com.example.kafkademo.api;

import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import com.example.kafkademo.producer.EventPublisher;

@RestController
@RequestMapping("/events")
public class EventController {

    private final EventPublisher publisher;

    public EventController(EventPublisher publisher) {
        this.publisher = publisher;
    }

    @PostMapping
    public ResponseEntity<Void> publish(@RequestParam("type") String type, @RequestBody String payload) {
        publisher.publish(type, payload);
        return ResponseEntity.accepted().build();
    }
}

